import{_ as e,o as a,c as o,a2 as l}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"董事会与公司治理 Corporate Governance","description":"一个被严重低估的核心主题","frontmatter":{"title":"董事会与公司治理 Corporate Governance","description":"一个被严重低估的核心主题"},"headers":[],"relativePath":"02_concepts/corporate-governance.md","filePath":"02_concepts/corporate-governance.md"}'),r={name:"02_concepts/corporate-governance.md"};function h(p,t,n,s,i,d){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="董事会与公司治理-corporate-governance" tabindex="-1">董事会与公司治理 Corporate Governance <a class="header-anchor" href="#董事会与公司治理-corporate-governance" aria-label="Permalink to &quot;董事会与公司治理 Corporate Governance&quot;">​</a></h1><blockquote><p>&quot;董事会存在的意义，是确保公司为股东服务，而不是管理层为自己服务。如果董事会做不到这一点，股东就是砧板上的鱼肉。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a></p></blockquote><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;">**[[/01_letters/1992年/核心总结</td><td style="text-align:left;">1992年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/1993年/核心总结</td><td style="text-align:left;">1993年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2002年/核心总结</td><td style="text-align:left;">2002年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2003年/核心总结</td><td style="text-align:left;">2003年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2008年/核心总结</td><td style="text-align:left;">2008年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2014年/核心总结</td><td style="text-align:left;">2014年]]**</td></tr><tr><td style="text-align:left;">**[[/01_letters/2018年/核心总结</td><td style="text-align:left;">2018年]]**</td></tr></tbody></table><p>:::{.callout .note} <strong>数据注脚</strong>：在整个巴菲特股东信语料库中，&quot;董事会&quot;一词出现<strong>863次</strong>，2014年单年达到<strong>101次</strong>峰值——这一主题被市场严重低估，却是理解现代公司治理痼疾的关键切口。 :::</p><hr><h2 id="为什么董事会问题长期被忽视" tabindex="-1">为什么董事会问题长期被忽视？ <a class="header-anchor" href="#为什么董事会问题长期被忽视" aria-label="Permalink to &quot;为什么董事会问题长期被忽视？&quot;">​</a></h2><p>大多数投资者在分析一家公司时，首先看财务数据、行业地位、管理团队——却很少有人真正审视那家公司的<strong>董事会结构</strong>。</p><p>这是一个危险的盲区。</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在1992年首次系统性地将矛头指向董事会问题。他指出：公司治理失败的根源，往往不是管理层&quot;变坏&quot;了，而是<strong>监督机制从一开始就是缺失的</strong>——而这个监督机制，正是董事会。</p><blockquote><p>&quot;我们经常听到投资者抱怨管理层的薪酬过高、并购决策愚蠢、信息披露不透明。但很少有人追问：是谁批准了这一切？是谁在监督管理层？答案是：董事会——一个在大多数公司里，几乎不发挥作用的机构。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1992年</p></blockquote><p>他用一个辛辣的比喻形容大多数美国公司董事会：<strong>&quot;看门狗&quot;被养在主人家里，却对主人摇尾巴。</strong></p><hr><h2 id="问题的根源-董事遴选机制的内在缺陷" tabindex="-1">问题的根源：董事遴选机制的内在缺陷 <a class="header-anchor" href="#问题的根源-董事遴选机制的内在缺陷" aria-label="Permalink to &quot;问题的根源：董事遴选机制的内在缺陷&quot;">​</a></h2><h3 id="你选我当董事-我选你当董事" tabindex="-1">&quot;你选我当董事，我选你当董事&quot; <a class="header-anchor" href="#你选我当董事-我选你当董事" aria-label="Permalink to &quot;&quot;你选我当董事，我选你当董事&quot;&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在1993年的信中，一针见血地指出了董事遴选机制的根本性问题：</p><blockquote><p>&quot;美国公司董事的提名，本质上是一种&#39;内部交易&#39;。现任 CEO 推荐下届董事候选人，下届董事在当选后投票支持现任 CEO——这是一套精心设计的互利机制，而不是为股东服务的机制。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1993年</p></blockquote><p>在这样的机制下，董事候选人最重要的&quot;资质&quot;，往往不是商业判断力、财务专业知识或独立性，而是<strong>与管理层的友好关系</strong>。</p><blockquote><p>&quot;我见过一些公司的董事会，里面坐满了退休的高管、学者的配偶、CEO 的大学同学——这些人有一个共同点：对管理层永远说&#39;是&#39;。他们不是坏蛋，他们只是没有资格扮演监督者的角色。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1993年</p></blockquote><h3 id="利益冲突-独立董事不独立" tabindex="-1">利益冲突：独立董事不独立 <a class="header-anchor" href="#利益冲突-独立董事不独立" aria-label="Permalink to &quot;利益冲突：独立董事不独立&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对&quot;独立董事&quot;（Independent Director）这一概念持深度怀疑态度——不是因为独立董事本身不好，而是因为<strong>现实中的&quot;独立&quot;往往是虚假的</strong>。</p><blockquote><p>&quot;公司董事会中，大多数董事在法律上被称为&#39;独立董事&#39;，但实际上，他们从公司获得的咨询费、演讲费、股票期权或慈善捐赠，远超他们的董事薪酬。在这种情况下，你怎么能期待他们真正&#39;独立&#39;？&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2003年</p></blockquote><p>他进一步解释：真正的独立，需要同时满足两个条件——<strong>既没有经济利益，也没有社会关系</strong>。而大多数公司董事会，这两个条件都难以满足。</p><blockquote><p>&quot;如果一个董事的儿子在为公司的投资银行工作，如果一个董事在公司的慈善基金会担任顾问，如果一个董事与管理层的核心成员是高尔夫球友——他们就不是独立的，无论他们的简历上怎么写。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2003年</p></blockquote><hr><h2 id="董事会的真正职责" tabindex="-1">董事会的真正职责 <a class="header-anchor" href="#董事会的真正职责" aria-label="Permalink to &quot;董事会的真正职责&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>并不认为董事会应该被废除——相反，他始终认为一个<strong>有效的</strong>董事会，是公司治理不可或缺的组成部分。关键在于，什么才是&quot;有效的董事会&quot;。</p><h3 id="职责一-选拔和监督ceo" tabindex="-1">职责一：选拔和监督CEO <a class="header-anchor" href="#职责一-选拔和监督ceo" aria-label="Permalink to &quot;职责一：选拔和监督CEO&quot;">​</a></h3><p>董事会的第一职责，是为股东挑选一位合格的 CEO，并在其任期内持续评估其表现。这包括：</p><ul><li>在 CEO 表现不佳时及时干预</li><li>在必要时果断更换 CEO</li><li>评估 CEO 的继任人选</li></ul><blockquote><p>&quot;董事会最重要的决定，是选择 CEO 这个决定。这个决定做对了，其他大多数决定都可以弥补；这个决定做错了，其他所有决定都无济于事。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1992年</p></blockquote><h3 id="职责二-资本配置监督" tabindex="-1">职责二：资本配置监督 <a class="header-anchor" href="#职责二-资本配置监督" aria-label="Permalink to &quot;职责二：资本配置监督&quot;">​</a></h3><p>董事会还应承担资本配置的监督责任——包括审批重大投资、收购、剥离和分红决策。</p><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>批评了许多公司董事会在重大并购案中的失职：董事们往往只是在管理层呈上的华丽PPT前点头通过，而没有进行 真正的问题不是他们不理解，而是他们从来不被要求去理解。&quot;</p><blockquote><p>——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2002年</p></blockquote><h3 id="职责三-高管薪酬的审核与约束" tabindex="-1">职责三：高管薪酬的审核与约束 <a class="header-anchor" href="#职责三-高管薪酬的审核与约束" aria-label="Permalink to &quot;职责三：高管薪酬的审核与约束&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>在2014年的信中，用大量篇幅专门讨论了薪酬委员会的问题。他指出：薪酬委员会通常由最听话的董事组成，而这些董事与 CEO 之间的关系，往往使他们无法真正履行监督职责。</p><blockquote><p>&quot;薪酬委员会的工作，本质上是与管理层谈判薪酬。但问题在于：这些委员会成员本身是由 CEO 挑选的，他们大多数人希望明年还在这个委员会里任职。这种利益冲突，使得高管薪酬失控成为常态，而不是例外。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2014年</p></blockquote><p>他补充了一个令人深思的数据：2003年至2012年的十年间，<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>旗下企业的 CEO 平均薪酬涨幅，远低于全行业平均水平——这不是因为伯克希尔吝啬，而是因为伯克希尔的薪酬设计是真正与业绩挂钩的。</p><hr><h2 id="金融危机揭示的系统性失败" tabindex="-1">金融危机揭示的系统性失败 <a class="header-anchor" href="#金融危机揭示的系统性失败" aria-label="Permalink to &quot;金融危机揭示的系统性失败&quot;">​</a></h2><p>2008年金融危机，是<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>观察公司治理失败的最好教材。那些倒闭或濒临破产的金融机构，无一例外地拥有相似的治理特征：董事会形同虚设、风险管理形同虚设、激励机制严重扭曲。</p><blockquote><p>&quot;雷曼兄弟的董事会，在破产前的最后一次会议上，批准了一笔数十亿美元的奖金发放。那些董事们知道公司正在崩溃吗？也许不知道。但更可能的是：他们选择了不知道，因为他们不想知道。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2008年</p></blockquote><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>指出：金融机构的治理失败有一个共同模式——风险被层层包装、层层隐瞒，最终到达董事会的只是一份光鲜的汇报材料，而没有人真正追问：&quot;如果我们错了呢？&quot;</p><hr><h2 id="巴菲特的董事会设计理念" tabindex="-1">巴菲特的董事会设计理念 <a class="header-anchor" href="#巴菲特的董事会设计理念" aria-label="Permalink to &quot;巴菲特的董事会设计理念&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对伯克希尔董事会结构的设计，体现了他对公司治理的全部思考。以下是他的核心设计原则：</p><h3 id="原则一-严格限制董事数量" tabindex="-1">原则一：严格限制董事数量 <a class="header-anchor" href="#原则一-严格限制董事数量" aria-label="Permalink to &quot;原则一：严格限制董事数量&quot;">​</a></h3><p><a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>的董事会规模长期维持在较小水平——只有少数几位董事，每个人都有足够的时间和精力深入了解公司业务。</p><blockquote><p>&quot;一个20人的董事会，是一个讨论俱乐部，不是决策机构。我宁愿与6个人深度讨论，也不愿意在20个人的会议室里举手表决。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，1992年</p></blockquote><h3 id="原则二-董事长与ceo的双重角色" tabindex="-1">原则二：董事长与CEO的双重角色 <a class="header-anchor" href="#原则二-董事长与ceo的双重角色" aria-label="Permalink to &quot;原则二：董事长与CEO的双重角色&quot;">​</a></h3><p>与大多数公司不同，<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>同时担任伯克希尔的董事长和 CEO。他明确表示，这一安排只适用于他本人——因为他的声誉和利益都与公司高度绑定，没有动机去做伤害股东的事情。</p><blockquote><p>&quot;我之所以兼任董事长，是因为我相信自己是为股东利益服务的最佳人选。但这不意味着所有公司都应该这样做。对于那些 CEO 能力一般、利益绑定不深的公司，分离董事长和 CEO 职位，是保护股东利益的重要机制。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2006年</p></blockquote><h3 id="原则三-拒绝外部顾问的薪酬委员会" tabindex="-1">原则三：拒绝外部顾问的薪酬委员会 <a class="header-anchor" href="#原则三-拒绝外部顾问的薪酬委员会" aria-label="Permalink to &quot;原则三：拒绝外部顾问的薪酬委员会&quot;">​</a></h3><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对薪酬委员会使用外部顾问持批评态度，因为这些顾问的收费对象，正是那些需要被监督的管理层。</p><blockquote><p>&quot;想象一下，你委托一个人去买东西，告诉他&#39;帮你自己选一辆车&#39;。这就是薪酬委员会使用管理层的顾问公司的逻辑。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2014年</p></blockquote><p>伯克希尔的薪酬设计由<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>亲力亲为，他直接与各业务负责人商定薪酬方案，确保薪酬真正反映业绩。</p><hr><h2 id="识别问题董事会的警示信号" tabindex="-1">识别问题董事会的警示信号 <a class="header-anchor" href="#识别问题董事会的警示信号" aria-label="Permalink to &quot;识别问题董事会的警示信号&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>总结了识别问题董事会的几个关键信号：</p><table tabindex="0"><thead><tr><th style="text-align:left;">警示信号</th><th style="text-align:left;">具体表现</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>董事任期过长</strong></td><td style="text-align:left;">超过15年未更换，关系过于稳固</td></tr><tr><td style="text-align:left;"><strong>CEO 掌控董事提名</strong></td><td style="text-align:left;">候选人主要由 CEO 推荐产生</td></tr><tr><td style="text-align:left;"><strong>关联交易频繁</strong></td><td style="text-align:left;">董事与公司存在大量商业往来</td></tr><tr><td style="text-align:left;"><strong>薪酬失控</strong></td><td style="text-align:left;">高管薪酬与业绩严重脱钩</td></tr><tr><td style="text-align:left;"><strong>审计委员会走过场</strong></td><td style="text-align:left;">审计报告由管理层选择的审计机构出具</td></tr><tr><td style="text-align:left;"><strong>缺乏行业专家</strong></td><td style="text-align:left;">董事会无人真正理解公司所在行业</td></tr></tbody></table><blockquote><p>&quot;如果你在研究一家公司时，发现上述信号中有三个以上同时出现，我建议你认真考虑是否还要持有这家公司的股票。&quot; ——<a href="/04_people/沃伦·巴菲特.html">沃伦·巴菲特</a>，《<a href="/03_companies/伯克希尔哈撒韦.html">伯克希尔</a>·哈撒韦致股东信》，2003年</p></blockquote><hr><h2 id="对投资者的真正意义" tabindex="-1">对投资者的真正意义 <a class="header-anchor" href="#对投资者的真正意义" aria-label="Permalink to &quot;对投资者的真正意义&quot;">​</a></h2><p>理解董事会与公司治理，对普通投资者究竟有什么实际价值？</p><p><strong>第一，它解释了为什么好公司也会变坏。</strong></p><p>许多曾经优秀的公司走向衰落，并不是因为行业不行了，而是因为<strong>监督机制失灵</strong>——管理层的自大、贪婪和短视，缺乏来自董事会的有效约束。</p><p><strong>第二，它提供了一个独特的分析角度。</strong></p><p>当所有人都盯着财务数据和技术指标时，审视一家公司的治理结构，可以帮助你发现别人忽视的风险。</p><p><strong>第三，它与<a href="/04_people/沃伦·巴菲特.html">巴菲特</a>的管理层选择理念一脉相承。</strong></p><p>一个好的董事会，往往能够吸引和留住优秀的管理者；一个坏的董事会，则会驱逐优秀的管理者，留下的只有那些愿意配合的人。</p><hr><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p><a href="/04_people/沃伦·巴菲特.html">巴菲特</a>对董事会的思考，揭示了一个被市场长期忽视的真相：<strong>公司治理不是形式，而是实质</strong>。</p><p>董事会的质量，决定了管理层的行为边界；董事遴选的机制，决定了董事会的质量。而这一切的根源，又回到了人——选择什么样的人进入董事会，决定了这家公司最终会走向何方。</p><p><strong>投资者在评估一家公司时，不应该只问&quot;管理层有多强&quot;，还应该问&quot;谁来监督管理层&quot;。</strong></p>',77)])])}const q=e(r,[["render",h]]);export{c as __pageData,q as default};
